#include <stdio.h>
#include <string.h>

int minBlocks(char *A, char *B, int N, int M) {
    int i, j, count = 1;
    i = j = 0;
    while (i < N || j < M) {
        if (i < N && (j == M || A[i] < B[j])) {
            if (i > 0 && A[i] != A[i - 1]) count++;
            i++;
        } else {
            if (j > 0 && B[j] != B[j - 1]) count++;
            j++;
        }
    }
    return count;
}

int main() {
    int T, N, M;
    char A[5005], B[5005];
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &M);
        scanf("%s", A);
        scanf("%s", B);
        printf("%d\n", minBlocks(A, B, N, M));
    }
    return 0;
}

