import java.util.Scanner;
public class Main {
    public static int minBlocks(String A, String B, int N, int M) {
        int i, j, count = 1;
        i = j = 0;
        while (i < N || j < M) {
            if (i < N && (j == M || A.charAt(i) < B.charAt(j))) {
                if (i > 0 && A.charAt(i) != A.charAt(i - 1)) count++;
                i++;
            } else {
                if (j > 0 && B.charAt(j) != B.charAt(j - 1)) count++;
                j++;
            }
        }
        return count;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int M = sc.nextInt();
            String A = sc.next();
            String B = sc.next();
            System.out.println(minBlocks(A, B, N, M));
        }
    }
}

